TFTP CLIENT SESSION MACROS
════════════════════════════════════════════════

Launch:
  socwrap --macros --macro-file tftp.json -p 'tftp > ' -- tftp

SETUP:
  //set HOST 192.168.1.1         TFTP server address
  //set PORT 69                  TFTP server port (default 69)
  //set FILE firmware.bin         File to get or put
  //set LOCAL localfile.bin       Local filename (optional)

CONNECTION:
  //connect       Connect to {{HOST}} on port {{PORT}}
  //connect69     Connect to {{HOST}} on default port 69

TRANSFER MODE:
  //binary        Set binary (octet) transfer mode
  //ascii         Set ASCII (netascii) transfer mode

FILE OPERATIONS:
  //get           Get {{FILE}} from server
  //get-as        Get {{FILE}} and save as {{LOCAL}}
  //put           Put {{FILE}} to server
  //put-as        Put {{LOCAL}} to server as {{FILE}}

SESSION:
  //status        Show connection status
  //verbose       Toggle verbose mode
  //trace         Toggle packet tracing
  //quit          End TFTP session

QUICK ONE-SHOT (run outside tftp, via bash):
  //oneshot-get   tftp one-liner to get {{FILE}}
  //oneshot-put   tftp one-liner to put {{FILE}}

NOTES:
  - Always //connect before get/put operations
  - Use //binary for firmware, images, archives
  - Use //ascii for config files, text
  - TFTP has no authentication — use only on trusted networks
  - Default blocksize is 512 bytes; some servers support larger
  - TFTP uses UDP, not TCP
